        stagnation_count++;
        if (stagnation_count > 50 || temperature < 0.01) {
            // Increase temperature with randomization
            temperature = 20.0 * (0.5 + 0.5*(double)rand()/RAND_MAX);
            stagnation_count = 0;
            accept_count = 0;
        }
    } else {
        stagnation_count = 0;
    }
